import React from 'react';
import algoliasearch from 'algoliasearch';
import { InstantSearch, SearchBox, connectHits, connectPagination, Configure, RefinementList, CurrentRefinements, Stats } from 'react-instantsearch-dom';
import { GoogleMapsLoader, GeoSearch, Marker } from 'react-instantsearch-dom-maps';


import './App.css';


const searchClient = algoliasearch('0HAV8OIN0H', '34a2bb37ce4654ab910fc2fbee812efd');
const  index = searchClient.initIndex("Housing");

const Pagination = ({ currentRefinement, nbPages, refine, showPrevious, showNext }) => {
    let page = currentRefinement;
    return(
        <div className="pagination">
            <div className="results">
                <Stats
                    translations={{
                        stats(nbHits) {
                            return `${nbHits} results`;
                        },
                    }}
                />
            </div>
            <div className="navigation">
                <p>Page {currentRefinement}</p>
                <div className="arrows">
                    <a
                        className="prev-page arrow"
                        href="#"
                        onClick={event => {
                            event.preventDefault();
                            if(page>1) page=currentRefinement-1
                            refine(page);
                        }}
                    ><span>&#60;</span></a>
                    <a
                        className="next-page arrow"
                        href="#"
                        onClick={event => {
                            event.preventDefault();
                            if(page<nbPages) page=currentRefinement+1;
                            refine(page);
                        }}
                    ><span>&#62;</span></a>
                </div>
            </div>
        </div>
    );
}

const CustomPagination = connectPagination(Pagination);

const hits = ({ hits }) => {
    return(
        <div className="hits">
            <CustomPagination />
            {hits.map(hit => (
                <div key={hit.objectID}>
                    {hit.show_raw? <div className="hit">
                        <div className="left">
                            <div className="top-row">
                                <h2 className="name">{hit.property_name}</h2>
                                <p className="status">Pet policy status</p>
                            </div>
                            <div className="underline">
                                <div className="contacts">
                                    <p className="phone"><a href={"tel:"+hit.phone_raw.full}>{hit.phone_raw.formatted}</a></p>
                                    <p className="email">{ hit.email_raw.email ? <a href={"mail-to:"+hit.email_raw.email}>{hit.email_raw.email}</a> : "Don`t have an email"}</p>
                                </div>
                                <p className="status-info">{hit.pet_policy_status_raw}</p>
                            </div>
                            <p className="address">Address:
                                <br/>
                                <span>{hit.address_raw.formatted_value}</span>
                            </p>
                        </div>
                        <div className="right">
                            <p className="distance">9.2 Miles</p>
                            <a className="website" href={hit.website_raw.url} target="_blank" rel="noopener noreferrer">View website</a>
                        </div>
                    </div>: ''}
                </div>
            ))}
        </div>
    );
}

const CustomHits = connectHits(hits);

class FrontPage extends React.Component{
    constructor(props){
        super(props);
    }
    render(){
        return(<div className="container">
                <InstantSearch searchClient={searchClient} indexName="Housing">
                    <Configure hitsPerPage={3} />
                    <div className="row">
                        <div style={{ height: 500 }} className='col'>
                            <GoogleMapsLoader apiKey="AIzaSyBah20fW-PaxEEUXf7CrZGPp95PusGIL4A">
                                {google => (
                                    <GeoSearch
                                        enableRefineOnMapMove={true}
                                        enableRefine={true}
                                        initialZoom={4}
                                        google={google}
                                    >
                                        {({ hits }) => (
                                            <div>
                                                {hits.map(hit => hit.display? <Marker key={hit.objectID} hit={hit}/> : '')}
                                            </div>
                                        )}
                                    </GeoSearch>
                                )}
                            </GoogleMapsLoader>
                        </div>
                        <div className="col">
                            <SearchBox reset="reset"/>
                            <CustomHits />
                            <RefinementList attribute="show_raw" />
                        </div>
                    </div>

                </InstantSearch>
            </div>
        );
    }
}




export default FrontPage;
