import React from 'react';
import algoliasearch from 'algoliasearch/lite';
import { InstantSearch, SearchBox, connectHits } from 'react-instantsearch-dom';


import './App.css';


const searchClient = algoliasearch('0HAV8OIN0H', '34a2bb37ce4654ab910fc2fbee812efd');


const infiniteHits = ({ hits }) => (
    <div>
        {hits.map(hit => (
            <div key={hit.objectID}>
                <h2>Organization/Business Name: {hit.organization_name}</h2>
                <h3>Contact Person: {hit.contact_person}</h3>
                <p>Contact phone: <a href={"tel:"+hit.contact_number}>{hit.contact_number}</a></p>
                <p>Contact email: <a href={"mail-to:"+hit.contact_email}>{hit.contact_email}</a></p>
                <p>Address:
                    <br/>
                    <i>{hit.address.linel}, {hit.address.locality}, {hit.address.state}, {hit.address.postal_code}</i>
                </p>
                <p>Website: <a href={hit.website} target="_blank" rel="noopener noreferrer">{hit.website}</a></p>
                <p>Type of Organization: {hit.type_organisation}</p>
                <p>Community Offerings: {hit.community}</p>
            </div>
        ))}
    </div>
);
const CustomInfiniteHits = connectHits(infiniteHits);

const Partnership = () => (
    <div className="container">
        <InstantSearch searchClient={searchClient} indexName="Partners">
            <SearchBox />
            <CustomInfiniteHits />
        </InstantSearch>
    </div>
);




export default Partnership;
